import React, { useState } from 'react';

const App = () => {
  const [activeStep, setActiveStep] = useState(1);
  const [phoneNumber, setPhoneNumber] = useState('');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 rounded-lg shadow-lg w-11/12 md:w-8/12 lg:w-6/12 mx-auto">
        {activeStep === 1 ?
          <div className="p-4">
            <h2 className="text-lg font-bold mb-2">Verify Phone Number</h2>
            <input type="text" className="w-full p-2 mb-4 border border-gray-400 rounded-lg" value={phoneNumber} onChange={(e) => setPhoneNumber(e.target.value)} />
            <button className="bg-[#B7D7CD] py-2 px-4 rounded-lg text-white hover:bg-[#A9D8C5]">Submit</button>
          </div>
        : null}
        {activeStep === 2 ?
          <div className="p-4">
            <h2 className="text-lg font-bold mb-2">Install Authenticator App</h2>
            <p className="text-gray-400 mb-2">Please download and install an authenticator app on your device.</p>
          </div>
        : null}
        {activeStep === 3 ?
          <div className="p-4">
            <h2 className="text-lg font-bold mb-2">Generate Recovery Code</h2>
            <p className="text-gray-400 mb-2">Your recovery code has been generated.</p>
          </div>
        : null}
        <button className="bg-[#C06C88] py-2 px-4 rounded-lg text-white hover:bg-[#8E3857]" onClick={() => setActiveStep(activeStep + 1)}>
          Next Step
        </button>
      </div>
    </div>
  );
};

export default App;
